mapper.select:
SELECT
FROM market_contract_flat
ORDER BY contract_date DESC, contract_no LIMIT #{start}, #{length}

mapper.update:
UPDATE market_contract_flat
SET saved = #{saved}
WHERE contract_type = #{contractType}
  AND contract_no = #{contractNo}

mapper.select:
SELECT
FROM market_contract_grouped
ORDER BY first_contract_date DESC, group_key, vendor_biz_reg_no LIMIT #{start}, #{length}

mapper.update:
UPDATE market_contract_grouped
SET saved = #{saved}
WHERE contract_type = #{contractType}
  AND group_key = #{groupKey}

  AND vendor_biz_reg_no = #{vendorBizRegNo}
